<template><div class="composer"><div class="shortcuts"><button v-for="x in ['相册','小额打款','物流客服','邀请下单']" @click="$emit('action',x)">{{x}}</button></div><form @submit.prevent="send"><MessageSquare/><input v-model="text" placeholder="输入消息"/><Mic/><Smile/><button type="button" @click="$emit('more')"><Plus/></button><button v-if="text.trim()" class="send">发送</button></form></div></template><script setup lang="ts">import{ref}from'vue';import{MessageSquare,Mic,Smile,Plus}from'lucide-vue-next';const emit=defineEmits(['send','more','action']);const text=ref('');function send(){if(!text.value.trim())return;emit('send',text.value.trim());text.value=''}</script>
